param([int]$Port=8788)$l=[Net.HttpListener]::new();$l.Prefixes.Add("http://127.0.0.1:$Port/");$l.Start();while($l.IsListening){$c=$l.GetContext();$r=$c.Response;$r.Headers.Add('Access-Control-Allow-Origin','*');$r.Headers.Add('Access-Control-Allow-Headers','X-API-Key');if($c.Request.HttpMethod -eq 'OPTIONS'){$r.StatusCode=204;$r.Close();continue};try{$k=$c.Request.Headers['X-API-Key'];$v=$c.Request.QueryString['input'];$ips=if([Net.IPAddress]::TryParse($v,[ref]$null)){@($v)}else{[Net.Dns]::GetHostAddresses($v)|% IPAddressToString|select -Unique};$d=@();foreach($ip in $ips){$d+=(Invoke-RestMethod "https://api.abuseipdb.com/api/v2/check?ipAddress=$ip&maxAgeInDays=182&verbose" -Headers @{Key=$k;Accept='application/json'}).data};$b=@{data=$d}|ConvertTo-Json -Depth 8;$r.StatusCode=200}catch{$b=@{error=$_.Exception.Message}|ConvertTo-Json;$r.StatusCode=502};$z=[Text.Encoding]::UTF8.GetBytes($b);$r.ContentType='application/json';$r.OutputStream.Write($z,0,$z.Length);$r.Close()}
